    ".googleapis.com",  # FCM (Chrome / Brave / Chromium Edge)
    ".push.services.mozilla.com",  # Firefox
    ".push.apple.com",  # Safari / iOS
    ".notify.windows.com",  # WNS (legacy Edge)
