        (t_write - t_start) * 1000,
        (t_probe - t_write) * 1000,
        (t_frames_end - t_frames_start) * 1000,
        mod_frames,
        (t_frames_end - t_start) * 1000,
    )

    return {
        "url": f"/chat/uploads/{filename}",
