  if (el) { el.classList.remove('open'); setTimeout(() => el.remove(), 200); }
}

// First-run notification prompt: shown once when notifications are off,
// never again after the user answers (either way) or explicitly disables.
let _notifPromptChecked = false;
function _maybePromptNotifications() {
  if (_notifPromptChecked) return;
  _notifPromptChecked = true;
  if (!('Notification' in window) || !('serviceWorker' in navigator) || !('PushManager' in window)) {
    dbg('[NOTIFY] first-run prompt skipped: push unsupported here');
    return;
  }
  if (storageGet('notif_prompt_done') === '1') { dbg('[NOTIFY] first-run prompt skipped: already answered'); return; }
  if (Notification.permission === 'denied') { dbg('[NOTIFY] first-run prompt skipped: permission denied in browser'); return; }
  if (storageGet('push_enabled') === '1' || (Notification.permission === 'granted' && _pushSubscribed)) {
    dbg('[NOTIFY] first-run prompt skipped: already enabled');
    return;
  }
  dbg('[NOTIFY] showing first-run enable prompt');
  document.getElementById('notif-prompt-modal')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'notif-prompt-modal';
  overlay.className = 'modal-overlay';
  overlay.innerHTML = `<div class="modal" role="dialog" aria-modal="true" aria-labelledby="notif-prompt-title" onclick="event.stopPropagation()">
    <div class="modal-header">
      <span class="modal-title" id="notif-prompt-title">Enable notifications?</span>
      <button class="modal-close" onclick="_answerNotifPrompt(false)">&times;</button>
    </div>
    <div class="modal-body" style="text-align:center">
      <p style="color:var(--color-muted);font-size:var(--font-sm);margin:0">
        Get notified when new messages arrive in your DMs, meetups, and rooms &mdash; even when the app is closed.
      </p>
    </div>
    <div class="modal-footer" style="display:flex;flex-direction:column;gap:8px">
      <button class="modal-btn-primary" onclick="_answerNotifPrompt(true)">Enable notifications</button>
      <button class="modal-btn-secondary" style="width:100%" onclick="_answerNotifPrompt(false)">Not now</button>
    </div>
  </div>`;
  overlay.addEventListener('click', () => _answerNotifPrompt(false));
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('open'));
}

function _answerNotifPrompt(enable) {
  dbg('[NOTIFY] first-run prompt answered:', enable ? 'enable' : 'skip');
  storageSet('notif_prompt_done', '1');
  const el = document.getElementById('notif-prompt-modal');
  if (el) { el.classList.remove('open'); setTimeout(() => el.remove(), 200); }
  if (enable) _enableAllNotifications();
}

async function _enableAllNotifications() {
  dbg('[NOTIFY] enableAllNotifications');
  const perm = await Notification.requestPermission();
  if (perm !== 'granted') {
    showToast('Permission denied. Check browser settings.');
    closeNotificationsModal();
    return;
  }
  const subscribed = await _subscribePush();
  _pushSubscribed = subscribed;
  if (subscribed) {
    storageSet('push_enabled', '1');
    showToast('Notifications enabled');
  } else {
    dbg('[NOTIFY] push subscribe failed, falling back to in-app-only');
    showToast('In-app alerts enabled. Push registration failed - if you use Brave, enable "Use Google services for push messaging" in brave://settings/privacy and try again.');
  }
  closeNotificationsModal();
}

async function _disableAllNotifications() {
  dbg('[NOTIFY] disableAllNotifications');
  if ('serviceWorker' in navigator && 'PushManager' in window) {
    try {
      const reg = await navigator.serviceWorker.ready;
      const sub = await reg.pushManager.getSubscription();
      if (sub) {
        const endpoint = sub.endpoint;
        await sub.unsubscribe();
        await fetch(API + '/push/subscribe', {
          method: 'DELETE', credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ endpoint }),
        });
        dbg('[NOTIFY] push unsubscribed');
      }
    } catch (e) {
      dbg('[NOTIFY] push unsubscribe failed', e);
    }
  }
  _pushSubscribed = false;
  storageRemove('push_enabled');
  // An explicit disable counts as answering the first-run prompt --
  // never nag this user about enabling again.
  storageSet('notif_prompt_done', '1');
  showToast('Notifications disabled. Disable in-app alerts in browser settings.');
  closeNotificationsModal();
}

